def suggest_chart(question: str, var_types: list[str]) -> str:
    """Map variable roles to a chart family — not a plotting call."""
    roles = set(var_types)
    if roles == {"categorical"}:
        return "bar"
    if roles == {"numeric"}:
        return "histogram"
    if roles == {"numeric", "categorical"}:
        return "box"
    if roles == {"numeric", "numeric"}:
        return "scatter"
    if roles == {"numeric", "ordered"}:
        return "line"
    if roles == {"matrix"}:
        return "heatmap"
    return "clarify question and variable types"

print(suggest_chart("class counts", ["categorical"]))           # bar
print(suggest_chart("feature A vs B", ["numeric", "numeric"]))  # scatter
print(suggest_chart("loss per epoch", ["numeric", "ordered"]))  # line
